async function handler(state, params) {
  const userEnv = state?.environment?.user ?? {};
  const prefix = typeof userEnv.GREETING_PREFIX === 'string' ? userEnv.GREETING_PREFIX : 'Hello';
  const name = typeof params?.name === 'string' ? params.name : 'world';
  return { ok: true, greeting: `${prefix}, ${name}!` };
}
